mapper.select:
select from project where deleted = 0 and id in
#{projectId}
and (project_name like concat('%', #{keyword}, '%') or project_code like concat('%', #{keyword}, '%'))
and status = #{status}
order by created_at desc, id desc

mapper.insert:
insert into project (
    project_name, project_code, location, status, description, created_by, updated_by
) values (
    #{projectName}, #{projectCode}, #{location}, #{status}, #{description}, #{createdBy}, #{updatedBy}
)

mapper.update:
update project
set deleted = 1, updated_by = #{updatedBy}
where id = #{projectId}
  and deleted = 0

update project
set status = #{status}, updated_by = #{updatedBy}
where id = #{projectId}
  and deleted = 0

update project
set settings = #{settings}, updated_by = #{updatedBy}
where id = #{projectId}
  and deleted = 0
